from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an athlete (or related entities) into a single fluent sentence.
    """
    if not triples:
        return ""

    # Build entity relationships to create connected sentences
    entity_info = {}
    all_subjects = set()
    all_objects = set()

    for triple in triples:
        subj = triple.subject
        pred = triple.predicate.lower()
        obj = triple.object

        all_subjects.add(subj)
        all_objects.add(obj)

        if subj not in entity_info:
            entity_info[subj] = []
        entity_info[subj].append((pred, obj))

    # Find main subject (athlete or most connected entity)
    # Prioritize athletes (names with spaces and common athlete patterns)
    athlete_keywords = ['FC', 'United', 'Club', 'Rams', 'Titans', 'Dolphins', 'Blues']
    main_subject = None
    for subj in entity_info.keys():
        if any(keyword in subj for keyword in athlete_keywords) or ' ' in subj:
            main_subject = subj
            break
    if main_subject is None:
        main_subject = max(entity_info.keys(), key=lambda s: len(entity_info[s]))

    # Build a chain of connected clauses using entity linking
    processed_triples = set()
    all_clauses = []

    def get_clause_text(subj, pred, obj, is_first=False):
        """Convert a triple to natural language text"""
        if pred == "birthDate":
            return f"was born on {obj}"
        elif pred == "birthYear":
            return f"was born in {obj}"
        elif pred == "birthPlace":
            return f"was born in {obj}"
        elif pred == "height":
            return f"measures {obj} in height"
        elif pred == "weight":
            return f"weighs {obj}"
        elif pred == "league":
            return f"plays in {obj}"
        elif pred == "club":
            return f"plays for {obj}"
        # currentclub handled above in club section
        elif pred == "currentteam":
            return f"currently plays for {obj}"
        elif pred == "formerTeam":
            return f"previously played for {obj}"
        elif pred == "currentclub":
            return f"currently plays for {obj}"
        elif pred == "position":
            return f"plays as a {obj}"
        elif pred == "manager":
            return f"is managed by {obj}"
        elif pred == "coach":
            return f"is coached by {obj}"
        elif pred == "owner":
            return f"is owned by {obj}"
        elif pred == "city":
            return f"based in {obj}"
        elif pred == "country":
            return f"from {obj}"
        elif pred == "isPartOf":
            return f"part of {obj}"
        elif pred == "season":
            return f"played during the {obj} season"
        elif pred == "foundingDate":
            return f"founded on {obj}"
        elif pred == "utcOffset":
            return f"UTC offset is {obj}"
        elif pred == "timeZone":
            return f"time zone is {obj}"
        elif pred == "areaTotal":
            return f"area is {obj}"
        elif pred == "demonym":
            return f"residents are called {obj}"
        elif pred == "language":
            return f"language is {obj}"
        elif pred == "officialLanguage":
            return f"official language is {obj}"
        elif pred == "anthem":
            return f"anthem is {obj}"
        elif pred == "leader":
            return f"leader is {obj}"
        elif pred == "leaderTitle":
            return f"leader title is {obj}"
        elif pred == "mostChampions":
            return f"most champions is {obj}"
        elif pred == "currency":
            return f"currency is {obj}"
        elif pred == "draftTeam":
            return f"drafted by {obj}"
        elif pred == "draftPick":
            return f"draft pick {obj}"
        elif pred == "draftRound":
            return f"draft round {obj}"
        elif pred == "draftYear":
            return f"draft year {obj}"
        elif pred == "playerNumber":
            return f"player number {obj}"
        elif pred == "college":
            return f"college is {obj}"
        elif pred == "debutTeam":
            return f"debuted with {obj}"
        elif pred == "activeYearsStartYear":
            return f"active since {obj}"
        elif pred == "universityTeam":
            return f"university team is {obj}"
        elif pred == "stadium":
            return f"stadium is {obj}"
        elif pred == "generalManager":
            return f"general manager is {obj}"
        elif pred == "chairman":
            return f"chairman is {obj}"
        elif pred == "deathPlace":
            return f"died in {obj}"
        elif pred == "ethnicGroup":
            return f"ethnic group is {obj}"
        else:
            return f"{pred} {obj}"

    # Process main subject's triples first
    main_clauses = []
    for pred, obj in entity_info.get(main_subject, []):
        clause = get_clause_text(main_subject, pred, obj)
        main_clauses.append(clause)
        processed_triples.add((main_subject, pred, obj))

    # Now find and connect related entities (when one object is another subject)
    # Build relative clauses for connected entities
    connected_clauses = []
    for subj in entity_info.keys():
        if subj == main_subject:
            continue
        for pred, obj in entity_info[subj]:
            if (subj, pred, obj) not in processed_triples:
                clause = get_clause_text(subj, pred, obj)
                # Check if this entity is connected to main_subject
                # If obj appears in main_subject's triples, create a relative clause
                is_connected = False
                for main_pred, main_obj in entity_info.get(main_subject, []):
                    if main_obj == subj or main_obj == obj:
                        is_connected = True
                        break

                if is_connected:
                    # Create relative clause
                    connected_clauses.append(f"which {clause}")
                else:
                    connected_clauses.append(clause)
                processed_triples.add((subj, pred, obj))

    # Build the final sentence - ALL information in ONE complex sentence
    all_clauses = main_clauses + connected_clauses

    if not all_clauses:
        return f"{main_subject}."

    # Start with main subject and first clause
    base = f"{main_subject} {all_clauses[0]}"

    # Connect remaining clauses with commas and 'and'
    for i, clause in enumerate(all_clauses[1:], 1):
        if i == len(all_clauses) - 1:
            base += f", and {clause}"
        else:
            base += f", {clause}"

    sentence = base + "."

    # Capitalize first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

